<script>
import { Carousel3d, Slide } from "vue-carousel-3d";
import axios from "axios";
// eslint-disable-next-line no-unused-vars
import { mapActions } from "vuex";
export default {
  data: () => ({
    page: 1,
    movies: [],
    dialog: true,
    loading: false,
    firstLoad: true,
    upcoming: [],
    attrs: {
      class: "mb-6",
      boilerplate: false,
      elevation: 2,
    },
    apiKey: "194d8a67379374e13e12c99420c19098",
    searchM: "",
    chips: [],
    example:
      "https://api.themoviedb.org/3/movie/550?api_key=194d8a67379374e13e12c99420c19098",
  }),
  methods: {
    ...mapActions(["A_enableDialog"]),

    saveToLocal(item) {
      // console.log("movie", item);
      sessionStorage.setItem("currentItem", JSON.stringify(item));
      window.scrollTo(0, 0);
    },
    async getNewPage() {
      sessionStorage.setItem("pageNumber", this.page);
      await axios
        .get(
          `https://api.themoviedb.org/3/movie/popular?api_key=${this.apiKey}&language=en-US&page=${this.page}`
        )
        .then((resp) => {
          this.movies = resp.data.results;
          // console.log(this.movies);
          this.A_enableDialog(true);
          this.firstLoad = true;
          setTimeout(() => {
            this.A_enableDialog(false);
            this.firstLoad = false;
            this.dialog = false;
            window.scrollTo({
              behavior: "smooth",
              top: 0,
            });
            // this.checkIfUpdated();
          }, 1500);
        });
    },
    checkIfUpdated() {
      const readyHandler = () => {
        if (document.readyState == "complete") {
          // console.log("movies updated completed");
          setTimeout(() => {
            // this.firstLoad = false;
          }, 1500);
          document.removeEventListener("readystatechange", readyHandler);
        }
      };
      document.addEventListener("readystatechange", readyHandler);
      readyHandler();
    },
  },
  async mounted() {
    this.$route.params.id = this.page;
    // console.log(this.$route.params.id);
    if (sessionStorage.getItem("pageNumber")) {
      this.page = Number(sessionStorage.getItem("pageNumber"));
    }
    this.getNewPage();
    await axios
      .get(
        `https://api.themoviedb.org/3/genre/movie/list?api_key=${this.apiKey}&language=en-US`
      )
      .then((resp) => {
        this.chips = resp.data.genres;
      });
    await axios
      .get(
        `https://api.themoviedb.org/3/movie/upcoming?api_key=${this.apiKey}&language=en-US&page=1`
      )
      .then((resp) => {
        this.upcoming = resp.data.results;
      });
  },
  computed: {
    posterPath(movie) {
      return "https://image.tmdb.org/t/p/w500" + movie.poster_path;
    },
  },
  created() {
    const readyHandler = () => {
      if (document.readyState == "complete") {
        // console.log("movies complete");
        setTimeout(() => {
          this.firstLoad = false;
        }, 1500);
        document.removeEventListener("readystatechange", readyHandler);
      }
    };
    document.addEventListener("readystatechange", readyHandler);
    readyHandler();
  },
  /* eslint-disable vue/no-unused-components */
  /* eslint-disable vue/no-async-in-computed-properties */

  components: {
    Carousel3d,
    Slide,
  },
};
</script>

